#!/usr/bin/env python3
"""
Dependency Lock Management (pip-compile or Poetry)

This script is both a reference document and an automation tool for consistent
Python dependency versions across development and production.

Supports two workflows:
  1) pip-tools (requirements.in -> requirements.txt with hashes)
  2) Poetry (pyproject.toml -> poetry.lock)

Why lock files:
  - Ensures reproducible installs across machines/CI/production
  - Prevents accidental upgrades via transitive dependencies
  - Enables secure installs with hash-checking (pip requirements.txt w/ hashes)

------------------------------------------------------------------------------
WORKFLOW A: pip-tools (recommended for pip/requirements users)
------------------------------------------------------------------------------

Files:
  - requirements.in         # Direct (top-level) runtime dependencies only
  - requirements-dev.in     # Dev dependencies (linters, test tools, etc.)
  - requirements.txt        # Fully pinned runtime dependencies (generated)
  - requirements-dev.txt    # Fully pinned dev dependencies (generated)

Rules:
  - Only edit *.in files by hand
  - Never hand-edit *.txt lock files; they are generated
  - Commit both *.in and *.txt files to version control
  - Use hashes in requirements.txt for supply-chain integrity

Installation:
  pip install pip-tools

Generate/Update locks:
  - Initial generation:
      pip-compile --generate-hashes -o requirements.txt requirements.in
      pip-compile --generate-hashes -o requirements-dev.txt requirements-dev.in
  - Upgrade all deps (major/minor/patch as allowed by .in specifiers):
      pip-compile --upgrade --generate-hashes -o requirements.txt requirements.in
  - Upgrade a single package (and its transitive deps as needed):
      pip-compile --upgrade-package PACKAGE --generate-hashes -o requirements.txt requirements.in

Install from locks (reproducible):
  pip install --require-hashes -r requirements.txt
  pip install --require-hashes -r requirements-dev.txt

Notes:
  - Keep requirements.in minimal:
      Example: requests>=2.31,<3
  - For services that must match prod, deploy using the same lock file.
  - Use constraints if you need to cap transitive versions:
      pip-compile supports constraints files and inclusion patterns.

------------------------------------------------------------------------------
WORKFLOW B: Poetry (recommended for Poetry users)
------------------------------------------------------------------------------

Files:
  - pyproject.toml   # Direct dependencies and constraints
  - poetry.lock      # Fully resolved dependency graph (generated)

Rules:
  - Edit pyproject.toml for adding/updating dependencies
  - Commit poetry.lock
  - Use the same Poetry version in CI as developers (pin via tooling)

Installation:
  pipx install poetry
  or
  pip install poetry

Generate/Update lock:
  - Create or refresh lock (do not update versions):
      poetry lock --no-update
  - Update all dependencies (within constraints):
      poetry update
  - Update a single dependency:
      poetry update PACKAGE

Install:
  - Sync environment exactly to lock:
      poetry install --sync

Export to requirements (if needed for production systems that use pip):
  poetry export -f requirements.txt --output requirements.txt --with-hashes

------------------------------------------------------------------------------
RECOMMENDED TEAM PRACTICES
------------------------------------------------------------------------------

1) Choose ONE primary lock strategy per repo (pip-tools OR Poetry).
2) Lock files must be committed and used everywhere (dev, CI, prod).
3) Use automation:
   - CI should fail if lock files are out of date with source specs.
4) Prefer hash-based installs for pip (pip-tools or poetry export --with-hashes).
5) Periodic maintenance:
   - Monthly dependency upgrade PR
   - Security-driven upgrades as needed

------------------------------------------------------------------------------
USAGE (this script)
------------------------------------------------------------------------------

This tool wraps common commands and adds safety checks.

Examples:

pip-tools workflow:
  ./dep_lock.py piptools-init
  ./dep_lock.py piptools-lock
  ./dep_lock.py piptools-upgrade
  ./dep_lock.py piptools-upgrade-package requests
  ./dep_lock.py piptools-install
  ./dep_lock.py piptools-verify-clean

Poetry workflow:
  ./dep_lock.py poetry-lock
  ./dep_lock.py poetry-update
  ./dep_lock.py poetry-update-package requests
  ./dep_lock.py poetry-install
  ./dep_lock.py poetry-export

Run:
  python dep_lock.py -h

Exit codes:
  0 success
  non-zero on failure

------------------------------------------------------------------------------
"""

from __future__ import annotations

import argparse
import os
import shutil
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, Optional


ROOT = Path.cwd()


@dataclass(frozen=True)
class CmdResult:
    returncode: int


def _which(prog: str) -> Optional[str]:
    return shutil.which(prog)


def run(cmd: Iterable[str], *, check: bool = True, cwd: Optional[Path] = None) -> CmdResult:
    cmd_list = list(cmd)
    p = subprocess.run(cmd_list, cwd=str(cwd or ROOT))
    if check and p.returncode != 0:
        raise SystemExit(p.returncode)
    return CmdResult(p.returncode)


def ensure_tool(prog: str, install_hint: str) -> None:
    if not _which(prog):
        print(f"ERROR: Required tool '{prog}' not found on PATH.", file=sys.stderr)
        print(f"Install hint: {install_hint}", file=sys.stderr)
        raise SystemExit(2)


def ensure_file(path: Path, content: str) -> None:
    if not path.exists():
        path.write_text(content, encoding="utf-8")
        print(f"Created {path}")
    else:
        print(f"Exists {path}")


def git_is_clean() -> bool:
    if not _which("git"):
        return True
    p = subprocess.run(["git", "status", "--porcelain"], capture_output=True, text=True)
    if p.returncode != 0:
        return True
    return p.stdout.strip() == ""


def git_require_clean() -> None:
    if not git_is_clean():
        print("ERROR: Working tree is not clean. Commit/stash changes before locking.", file=sys.stderr)
        raise SystemExit(3)


def piptools_init(args: argparse.Namespace) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")
    ensure_file(ROOT / "requirements.in", "# Top-level runtime deps only\n")
    ensure_file(ROOT / "requirements-dev.in", "-r requirements.in\n# Dev-only deps (pytest, ruff, mypy, etc.)\n")
    print("pip-tools initialized. Edit *.in files, then run: dep_lock.py piptools-lock")


def piptools_lock(args: argparse.Namespace) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")
    if args.clean_git:
        git_require_clean()

    in_rt = ROOT / "requirements.in"
    in_dev = ROOT / "requirements-dev.in"
    if not in_rt.exists():
        print("ERROR: requirements.in not found. Run: dep_lock.py piptools-init", file=sys.stderr)
        raise SystemExit(2)

    cmd_rt = ["pip-compile", "--generate-hashes", "-o", "requirements.txt", str(in_rt)]
    cmd_dev = ["pip-compile", "--generate-hashes", "-o", "requirements-dev.txt", str(in_dev)] if in_dev.exists() else None

    if args.quiet:
        cmd_rt.insert(1, "--quiet")
        if cmd_dev:
            cmd_dev.insert(1, "--quiet")

    if args.resolver:
        cmd_rt.extend(["--resolver", args.resolver])
        if cmd_dev:
            cmd_dev.extend(["--resolver", args.resolver])

    run(cmd_rt)
    if cmd_dev:
        run(cmd_dev)


def piptools_upgrade(args: argparse.Namespace) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")
    if args.clean_git:
        git_require_clean()

    in_rt = ROOT / "requirements.in"
    if not in_rt.exists():
        print("ERROR: requirements.in not found. Run: dep_lock.py piptools-init", file=sys.stderr)
        raise SystemExit(2)

    cmd = ["pip-compile", "--upgrade", "--generate-hashes", "-o", "requirements.txt", str(in_rt)]
    if args.quiet:
        cmd.insert(1, "--quiet")
    if args.resolver:
        cmd.extend(["--resolver", args.resolver])
    run(cmd)

    in_dev = ROOT / "requirements-dev.in"
    if in_dev.exists():
        cmd_dev = ["pip-compile", "--upgrade", "--generate-hashes", "-o", "requirements-dev.txt", str(in_dev)]
        if args.quiet:
            cmd_dev.insert(1, "--quiet")
        if args.resolver:
            cmd_dev.extend(["--resolver", args.resolver])
        run(cmd_dev)


def piptools_upgrade_package(args: argparse.Namespace) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")
    if args.clean_git:
        git_require_clean()

    pkg = args.package
    in_rt = ROOT / "requirements.in"
    if not in_rt.exists():
        print("ERROR: requirements.in not found. Run: dep_lock.py piptools-init", file=sys.stderr)
        raise SystemExit(2)

    cmd = ["pip-compile", "--upgrade-package", pkg, "--generate-hashes", "-o", "requirements.txt", str(in_rt)]
    if args.quiet:
        cmd.insert(1, "--quiet")
    if args.resolver:
        cmd.extend(["--resolver", args.resolver])
    run(cmd)

    in_dev = ROOT / "requirements-dev.in"
    if in_dev.exists():
        cmd_dev = ["pip-compile", "--upgrade-package", pkg, "--generate-hashes", "-o", "requirements-dev.txt", str(in_dev)]
        if args.quiet:
            cmd_dev.insert(1, "--quiet")
        if args.resolver:
            cmd_dev.extend(["--resolver", args.resolver])
        run(cmd_dev)


def piptools_install(args: argparse.Namespace) -> None:
    req = ROOT / "requirements.txt"
    if not req.exists():
        print("ERROR: requirements.txt not found. Run: dep_lock.py piptools-lock", file=sys.stderr)
        raise SystemExit(2)
    cmd = [sys.executable, "-m", "pip", "install", "--require-hashes", "-r", str(req)]
    run(cmd)
    if args.dev:
        req_dev = ROOT / "requirements-dev.txt"
        if not req_dev.exists():
            print("ERROR: requirements-dev.txt not found. Run: dep_lock.py piptools-lock", file=sys.stderr)
            raise SystemExit(2)
        cmd_dev = [sys.executable, "-m", "pip", "install", "--require-hashes", "-r", str(req_dev)]
        run(cmd_dev)


def piptools_verify_clean(args: argparse.Namespace) -> None:
    ensure_tool("pip-compile", "pip install pip-tools")
    git_require_clean()
    before = subprocess.run(["git", "status", "--porcelain"], capture_output=True, text=True).stdout

    lock_args = argparse.Namespace(clean_git=False, quiet=True, resolver=args.resolver)
    piptools_lock(lock_args)

    after = subprocess.run(["git", "status", "--porcelain"], capture_output=True, text=True).stdout
    if after.strip() != before.strip():
        print("ERROR: Lock files changed. Commit updated lock files.", file=sys.stderr)
        print("Changed files:", file=sys.stderr)
        diff = subprocess.run(["git", "status", "--porcelain"], capture_output=True, text=True).stdout
        print(diff, file=sys.stderr)
        raise SystemExit(4)
    print("OK: Lock files are up to date and working tree remains clean.")


def poetry_lock(args: argparse.Namespace) -> None:
    ensure_tool("poetry", "pipx install poetry  # or: pip install poetry")
    if args.clean_git:
        git_require_clean()
    cmd = ["poetry", "lock"]
    if args.no_update:
        cmd.append("--no-update")
    run(cmd)


def poetry_update(args: argparse.Namespace) -> None:
    ensure_tool("poetry", "pipx install poetry  # or: pip install poetry")
    if args.clean_git:
        git_require_clean()
    run(["poetry", "update"])


def poetry_update_package(args: argparse.Namespace) -> None:
    ensure_tool("poetry", "pipx install poetry  # or: pip install poetry")
    if args.clean_git:
        git_require_clean()
    run(["poetry", "update", args.package])


def poetry_install(args: argparse.Namespace) -> None:
    ensure_tool("poetry", "pipx install poetry  # or: pip install poetry")
    cmd = ["poetry", "install", "--sync"]
    if args.without:
        cmd.extend(["--without", args.without])
    if args.with_groups:
        cmd.extend(["--with", args.with_groups])
    run(cmd)


def poetry_export(args: argparse.Namespace) -> None:
    ensure_tool("poetry", "pipx install poetry  # or: pip install poetry")
    out = args.output or "requirements.txt"
    cmd = ["poetry", "export", "-f", "requirements.txt", "--output", out]
    if args.with_hashes:
        cmd.append("--with-hashes")
    if args.without:
        cmd.extend(["--without", args.without])
    if args.with_groups:
        cmd.extend(["--with", args.with_groups])
    run(cmd)


def main() -> None:
    p = argparse.ArgumentParser(
        prog="dep_lock.py",
        description="Manage dependency lock files for reproducible Python environments (pip-tools or Poetry).",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    sub = p.add_subparsers(dest="cmd", required=True)

    s = sub.add_parser("piptools-init", help="Create starter requirements.in / requirements-dev.in files.")
    s.set_defaults(func=piptools_init)

    s = sub.add_parser("piptools-lock", help="Generate requirements*.txt from *.in with hashes.")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before generating.")
    s.add_argument("--quiet", action="store_true", help="Reduce pip-compile output.")
    s.add_argument("--resolver", choices=["backtracking", "legacy"], default=None, help="pip-tools resolver.")
    s.set_defaults(func=piptools_lock)

    s = sub.add_parser("piptools-upgrade", help="Upgrade and re-lock (within constraints).")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before upgrading.")
    s.add_argument("--quiet", action="store_true", help="Reduce pip-compile output.")
    s.add_argument("--resolver", choices=["backtracking", "legacy"], default=None, help="pip-tools resolver.")
    s.set_defaults(func=piptools_upgrade)

    s = sub.add_parser("piptools-upgrade-package", help="Upgrade a specific package and re-lock.")
    s.add_argument("package", help="Package name to upgrade.")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before upgrading.")
    s.add_argument("--quiet", action="store_true", help="Reduce pip-compile output.")
    s.add_argument("--resolver", choices=["backtracking", "legacy"], default=None, help="pip-tools resolver.")
    s.set_defaults(func=piptools_upgrade_package)

    s = sub.add_parser("piptools-install", help="Install from lock files using hash-checking.")
    s.add_argument("--dev", action="store_true", help="Also install dev lock file.")
    s.set_defaults(func=piptools_install)

    s = sub.add_parser("piptools-verify-clean", help="CI helper: re-lock and ensure git tree stays clean.")
    s.add_argument("--resolver", choices=["backtracking", "legacy"], default=None, help="pip-tools resolver.")
    s.set_defaults(func=piptools_verify_clean)

    s = sub.add_parser("poetry-lock", help="Generate/refresh poetry.lock.")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before locking.")
    s.add_argument("--no-update", action="store_true", help="Do not update versions, only refresh lock.")
    s.set_defaults(func=poetry_lock)

    s = sub.add_parser("poetry-update", help="Update all dependencies and lock.")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before updating.")
    s.set_defaults(func=poetry_update)

    s = sub.add_parser("poetry-update-package", help="Update a single dependency and lock.")
    s.add_argument("package", help="Package name to update.")
    s.add_argument("--clean-git", action="store_true", help="Require clean git working tree before updating.")
    s.set_defaults(func=poetry_update_package)

    s = sub.add_parser("poetry-install", help="Install exactly from poetry.lock (sync).")
    s.add_argument("--without", default=None, help="Exclude dependency group(s), comma-separated (Poetry v1.2+).")
    s.add_argument("--with-groups", default=None, help="Include dependency group(s), comma-separated.")
    s.set_defaults(func=poetry_install)

    s = sub.add_parser("poetry-export", help="Export lock to requirements.txt (optionally with hashes).")
    s.add_argument("--output", default=None, help="Output file (default requirements.txt).")
    s.add_argument("--with-hashes", action="store_true", help="Include hashes in exported requirements.")
    s.add_argument("--without", default=None, help="Exclude dependency group(s), comma-separated.")
    s.add_argument("--with-groups", default=None, help="Include dependency group(s), comma-separated.")
    s.set_defaults(func=poetry_export)

    args = p.parse_args()
    args.func(args)


if __name__ == "__main__":
    main()